from functools import lru_cache
@lru_cache(maxsize=None)
def A001190(n):
    if n <= 1: return n
    m = n//2 + n % 2
    return sum(A001190(i+1)*A001190(n-1-i) for i in range(m-1)) + (1 - n % 2)*A001190(m)*(A001190(m)+1)//2 # _Chai Wah Wu_, Jan 14 2022
def a(n_max):
    W = [0]*(n_max+2)
    for m in range(1, n_max):
        W[m] = A001190(m+1)
    B = [0]*(n_max+2)
    C = [0]*(n_max+2)
    C[1] = 1
    for m in range(2, n_max):
        total = C[m-1]
        for i in range(1, (m-1)//2+1):
            j = m-1-i
            if i < j:
                total += W[i]*C[j] + W[j]*C[i]
            else:
                total += C[i]*(W[i]+1)
        B[m] = total
        C[m] = B[m] + m*W[m]
    a = [0]*(n_max+1)
    a[1] = 0
    for N in range(2, n_max+1):
        m = N-1
        a[N] = C[m]
    return a[1:]

